        MAYBE_SOMEONE_SOMEWHEAHS_IN_THE_VICINITY_WINITY_OF                            = 10252,  -- Maybe someone somewheahs in the vicinity-winity of Yorcia Weald's frontieah station would know somethin'.
        GETTIN_TO_THE_WEALD_AIN_T_GONNA_BE                                            = 10253,  -- Gettin' to the weald ain't gonna be a picnic in the pahk, though. Ugh, even the Blackthohn Coven would be easiah to intaruview than Robertioux.
