        HEAR_YE_FIENDS_FROM_DIMENSIONS_UNKNOWN_WITH_MY                                = 10258,  -- Hear ye, fiends from dimensions unknown! With my arrival, the clouds shall part and Altana's holy light shall bathe thee in Her purifying radiance.
        RETURNEST_FROM_WHENCE_THOU_CAME_VILE_DEMONS                                   = 10259,  -- Returnest from whence thou came, vile demons!
