        OH_AND_WHO_MIGHT_YOU_BE_LOOKING_FORRR                                         = 10341,  -- Oh? And who might you be looking forrr?
        AHA_I_SEE_NOW_SO_YOU_LOST_THE                                                 = 10342,  -- Aha... I see now. So you lost the % that Erfimia gave you?
        SO_THAT_EXPLAINS_WHY_SHE_APPLIED_FOR_A                                        = 10343,  -- So that explains why she applied for a new one not long ago.
        YOU_KNOW_OUTSIDER_ARE_GIVEN_TO_FULL_EXORCISTS                                 = 10344,  -- You know, outsider, % are given to full exorcists as part of their confirmation. They aren't some common arrrticle you can find anywhere.
