        NOT_MANY_EXORCISTS_WORTH_THEIR_SALT_WOULD_EVER                                = 10348,  -- Not many exorcists worth their salt would ever lose theirs, so I'd wager that % is yourrrs.
        NORMALLY_WE_WOULD_NEVER_HAND_THE_PRIORY_S                                     = 10349,  -- Normally we would never hand the priory's property off to an outsider, so I reckon Erfimia must have had a verrry good reason in your case.
        I_LL_TELL_YOU_WHAT_IN_EXCHANGE_FOR                                            = 10350,  -- I'll tell you what, in exchange for a generrrous donation to the priory, I'll let you keep it.
        FANTASTIC_YOUR_DONATION_WILL_HELP_US_A_GRRREAT                                = 10351,  -- Fantastic! Your donation will help us a grrreat deal, I'm sure!
        THAT_WOULD_BE_FANTASTIC_HUH_UH_YOU_SEEM                                       = 10352,  -- That would be fantastic! Huh? Uh...you seem to be a little shorrrt on bayld, but...thanks for the thought.
        REALLY_I_M_SURE_ERFIMIA_WOULD_BE_HEARTBROKEN                                  = 10353,  -- Really? I'm sure Erfimia would be heartbroken if she ever found out you lost her prrrecious %...
