        WHAT_FOR_ME_I_M_SO_SORRY_I                                                    = 10360,  -- What? For me? I'm so sorry! I feel like I've coerced you into buying this for me. Feel being the operative word here.
        ALRIGHT_YOU_RE_DEFINITELY_THE_MAN_WOMAN_I                                     = 10361,  -- Alright, you're definitely the man/woman] I've been searching for! See, I'm a journalist working over in Western Adoulin.
        I_M_BUSY_GETTING_THE_LATEST_SCOOPS_FROM                                       = 10362,  -- I'm busy getting the latest scoops from around the city even as we speak.
