        OH_FATE_THOU_ART_A_CRUEL_AND_TERRIBLE                                         = 11140,  -- Oh, fate, thou art a cruel and terrible mistress!
        LISTEN_TO_THIS_THERE_I_WAS_PLANNING_OUT                                       = 11141,  -- %, listen to this! There I was, planning out the route I would take my beloved Yocile on--like any chivalrous gent would...
