        YOU_USED_THE_OLD_SWITCHEROO_YOUR_HAS_BEEN                                     = 12375,  -- You used the old switcheroo! Your # has been exchanged with your opponent's #, and your total is now #.
        YOU_FORCED_YOUR_OPPONENT_TO_SHOOT_AGAIN_HIS                                   = 12376,  -- You forced your opponent to shoot again! His shot for turn number # is now #.
