        CERTAIN_PRACTITIONERS_HAVE_IN_THESE_RECENT_YEARS_BEGUN                        = 12582,  -- Certain practitioners have, in these recent years, begun engraving runes into their flesh.
        THOSE_WHO_FAVOR_THIS_ROUTE_ARE_OFTEN_ROUTED                                   = 12583,  -- Those who favor this route are often routed in battle...be they not accompanied by an absorbent mind, quick reflexes, and an adaptive body.
