        ATTEMPT_TO_INSCRIBE_THE_HEAVENS_100_USE_RUNE                                  = 12609,  -- Attempt to inscribe the heavens? (#/100) Use Rune Enchantment...? ...I've had enough.
        THROWING_UP_YOUR_HANDS_AND_THROWING_IN_THE                                    = 12610,  -- Throwing up your hands and throwing in the towel, are you? But this is only attempt number #. The only thing that awaits you should you concede now is shame. Shame that will forever haunt you and your whole family.
