        TODAY_THE_WEATHER_IN_THAT_AREA_WILL_BE                                        = 13415,  -- Today, the weather in that area will be %. There is also the possibility of %, so caution is advised.
        TOMORROW_THE_WEATHER_WILL_BE_THERE_IS_ALSO                                    = 13416,  -- Tomorrow, the weather will be %. There is also the possibility of %, so caution is advised.
        AND_THE_DAY_AFTER_TOMORROW_THE_WEATHER_WILL_2                                 = 13417,  -- And, the day after tomorrow, the weather will be %. There is also the possibility of %, so caution is advised.
        THE_WEATHER_IN_THAT_AREA_TODAY_WILL_BE                                        = 13418,  -- The weather in that area today will be %.
        THE_WEATHER_TOMORROW_WILL_BE                                                  = 13419,  -- The weather tomorrow will be %.
        THE_WEATHER_THE_DAY_AFTER_TOMORROW_WILL_BE                                    = 13420,  -- The weather the day after tomorrow will be %.
        AND_THAT_S_THE_REPORT_STRAIGHT_FROM_VANA                                      = 13421,  -- And that's the report, straight from Vana'diel's official weather linkshell.
        WHAT_AREA_S_WEATHER_DO_YOU_WISH_TO_2                                          = 13422,  -- What area's weather do you wish to know? Nowhere. Wajaom Woodlands. Bhaflau Thickets. Mount Zhayolm. Caedarva Mire.
        WHAT_AREA_S_WEATHER_DO_YOU_WISH_TO_3                                          = 13423,  -- What area's weather do you wish to know? Nowhere. Ceizak Battlegrounds. Yahse Hunting Grounds. Foret de Hennetiel. Morimar Basalt Fields. Yorcia Weald. Marjami Ravine. Kamihr Drifts.
        PERHAPS_IT_WOULD_BEHOOVE_YOU_TO_SPEAK_WITH                                    = 13424,  -- Perhaps it would behoove you to speak with Rolandienne in Southern San d'Oria (G-10).
        PERHAPS_IT_WOULD_BEHOOVE_YOU_TO_SPEAK_WITH_2                                  = 13425,  -- Perhaps it would behoove you to speak with Isakoth in Bastok Markets (E-11).
        PERHAPS_IT_WOULD_BEHOOVE_YOU_TO_SPEAK_WITH_3                                  = 13426,  -- Perhaps it would behoove you to speak with Fhelm Jobeizat in Windurst Woods (J-10).
        PERHAPS_IT_WOULD_BEHOOVE_YOU_TO_SPEAK_WITH_4                                  = 13427,  -- Perhaps it would behoove you to speak with Eternal Flame in Western Adoulin (H-11).
        PERHAPS_IT_WOULD_BEHOOVE_YOU_TO_SPEAK_WITH_5                                  = 13428,  -- Perhaps it would behoove you to speak with Nantoto in Lower Jeuno (H-8).
        INVISIBLE_EYES_UPON_YOU_CAUSE_THE_HAIRS_ON                                    = 13429,  -- Invisible eyes upon you cause the hairs on the back of your neck to rise.
        THE_NODS_IN_AGREEMENT                                                         = 13430,  -- The % nods in agreement.
        A_NEW_RECORDS_OF_EMINENCE_OBJECTIVE_IS_NOW                                    = 13431,  -- A new Records of Eminence objective is now available!
        A_NEW_RECORDS_OF_EMINENCE_OBJECTIVE_IS_NOW_2                                  = 13432,  -- A new Records of Eminence objective, %, is now available!
        YOU_WISH_TO_EXCHANGE_YOUR_SPARKS                                              = 13433,  -- You wish to exchange your sparks?
        WAIT_BUT_A_MOMENT_HERE_FOLLOW_THIS_COMMAND                                    = 13434,  -- Wait but a moment. Here, follow this command--er, compendium to the letter and you should be able to learn a thing or two.
        AH_THIS_ALMOST_SLIPPED_MY_MIND_SHOULD_YOU                                     = 13435,  -- Ah, this almost slipped my mind. Should you receive any distinct sorts of artifacts for completing an objective, I will be happy to take them off your hands.
        WORRY_NOT_FOR_I_AM_NOT_OUT_TO                                                 = 13436,  -- Worry not, for I am not out to rob you of your glory. Quite the opposite, in fact. I will provide you with a worthwhile reward for collecting them.
        THANKS_TO_YOUR_DONATION_I_NOW_HAVE_IN                                         = 13437,  -- Thanks to your donation, I now have # in safekeeping.
        OHOHOHO_TURNING_IN_SPARKS_I_SEE                                               = 13438,  -- Ohohoho... Turning in sparks, I see.
        HOLD_YOUR_HOARDER_HARES_HERO_HEROINE_I_LOVE                                   = 13439,  -- Hold your hoarder hares, hero/heroine]. I love your enthusiasm, but you're not going to learn a thing without a primer. Ahhh, here it is. Have a look-see.
        OH_CRUD_THAT_S_RIGHT_YOU_SHOULD_TRADE                                         = 13440,  -- Oh, crud, that's right. You should trade me any special artifacts you get from completing objectives.
        WHY_WHAT_A_GOOD_QUESTION_BECAUSE_I_LL                                         = 13441,  -- Why? What a good question! Because I'll give you a nifty-difty reward at some point, that's why.
        THANKS_FOR_DOING_WHAT_I_ASKED_NOW_I                                           = 13442,  -- Thanks for doing what I asked. Now I have a total of # from you.
        YOU_WANT_TO_TRRRADE_IN_SPARKS_DO_YOU                                          = 13443,  -- You want to trrrade in sparks, do you?
        LET_ME_WAKE_UP_FROM_MY_CATNAP_FIRST                                           = 13444,  -- Let me wake up from my catnap first... Alright, now rrread this.
        WAIT_WAIT_WAIT_IF_YOU_HAPPEN_TO_GET                                           = 13445,  -- Wait, wait, wait! If you happen to get any purrrticularly interesting items from completing objectives, send them my way.
        DON_T_WORRY_I_M_AS_HONEST_AS                                                  = 13446,  -- Don't worry, I'm as honest as a cat when the meat's out of reach. I thought of taking them all for myself...
        BUT_I_DON_T_WANT_TO_MAKE_FUR                                                  = 13447,  -- ...but I don't want to make fur fly with the Adventurers' Mutual Aid Network, so I'll do my job like a good little kitty.
        GRRREAT_NOW_I_HAVE_FROM_YOU_THANKS                                            = 13448,  -- Grrreat! Now I have # from you. Thanks!
        HM_OH_SPARK_EXCHANGE_OF_COURSE                                                = 13449,  -- Hm? Oh, spark exchange... Of course.
        I_M_NOT_COMPLETELY_SURE_BUT_THIS_MIGHT                                        = 13450,  -- I'm not completely sure, but this might help set some things straight...I guess.
        LET_ME_ADD_ONE_THING_PLEASE_FIND_IT                                           = 13451,  -- Let me add one thing. Please find it within your heart of hearts to give me anything of particular interest you get from completing objectives.
        I_LL_MAKE_IT_WORTH_YOUR_WHILE_I                                               = 13452,  -- I'll make it worth your while...I swear! Just keep at it and I'll be sure to surprise you with a hot, steaming helping of gratitude one day.
        THANKS_FOR_DOING_YOUR_PART_IN_THE_BATTLE                                      = 13453,  -- Thanks for doing your part in the battle for love and peace! With this latest addition, I'm now keeping track of # for you.
        RECORDS_OF_EMINENCE_IS_A_SYSTEM_BROUGHT_TO                                    = 13454,  -- Records of Eminence is a system brought to you by the caring folks at the Adventurers' Mutual Aid Network. Set your own objectives whenever you desire, and fulfill them to receive compensation.
        TO_SET_THESE_TASKS_SELECT_OBJECTIVE_LIST_FROM                                 = 13455,  -- To set these tasks, select 'Objective List' from the Quests menu, then choose ones that suit your fancy.
        YOU_WILL_BE_REWARDED_WITH_GIL_AND_SPARKS                                      = 13456,  -- You will be rewarded with gil and sparks of eminence, which serve the same function as points, notes, credits, and other such methods of quantifying one's greatness. As an extra incentive, adventurers will earn three times the amount of sparks for completing an objective the first time.
        COMPLETED_OBJECTIVES_WILL_VANISH_FROM_YOUR_QUEST_LIST                         = 13457,  -- Completed objectives will vanish from your quest list unless they are repeatable. In the event that you wish to make room for different objectives, you will need to remove them manually.
        AS_A_COROLLARY_REGARDING_REWARDS_YOU_LL_BE                                    = 13458,  -- As a corollary regarding rewards, you'll be blessed with special remuneration once you complete several objectives. Bask in the joy of these pleasant surprises when you can.
        LASTLY_ANY_AND_ALL_ACTS_OF_VANDALISM_DIRECTED                                 = 13459,  -- Lastly, any and all acts of vandalism directed against your % are strictly prohibited.
        SHOULD_YOU_BE_FOUND_IN_VIOLATION_OF_THIS                                      = 13460,  -- Should you be found in violation of this dictum, the heavens will part and wrath incarnate will descend to mete out justice upon you.
        THE_MAXIMUM_NUMBER_OF_THAT_MAY_BE_STORED                                      = 13461,  -- The maximum number of % that may be stored is #.
        YOU_DO_NOT_POSSESS_ENOUGH_TO_COMPLETE_THE                                     = 13462,  -- You do not possess enough % to complete the transaction.
        YOU_DO_NOT_POSSESS_ENOUGH_SPARKS_OF_EMINENCE                                  = 13463,  -- You do not possess enough sparks of eminence to complete the transaction.
        YOU_HAVE_REACHED_THE_MAXIMUM_NUMBER_OF_SPARKS                                 = 13464,  -- You have reached the maximum number of sparks that you can exchange this week (#). Your ability to purchase skill books and equipment will be restricted until next week.
        YOU_MAY_USE_UP_TO_MORE_SPARKS_OF                                              = 13465,  -- You may use up to # more sparks of eminence to purchase items.
        EXCHANGE_FOR_WHAT_SPARKS_ITEMS_SKILL_INCREASING_TOMES                         = 13466,  -- Exchange for what? (Sparks: #) Items. Skill-increasing tomes. Equ. Lv.1 - 9. (Up to #) Equ. Lv.10 - 19. (Up to #) Equ. Lv.20 - 29. (Up to #) Equ. Lv.30 - 39. (Up to #) Equ. Lv.40 - 50. (Up to #) Equ. Lv.51 - 70. (Up to #) Equ. Lv.71 - 98. (Up to #) Equ. Lv.99. (Up to #) 10. Trust. Exchange A.M.A.N. currencies. Exchange Seven Treasures. Wise words on Records of Eminence. Nothing.
        EXCHANGE_UP_TO_SPA_SPARKS_PREVIOUS_PAGE_NEXT                                  = 13467,  -- Exchange up to # Spa. (Sparks: #) %. (#) %. (#) %. (#) %. (#) %. (#) %. (#) %. (#) %. (#) %. (#) %. (#) %. (#) %. (#) %. (#) %. (#) %. (#) Previous page. Next page. None.
        RECEIVE_HOW_MANY_SPARK_ONE_SPARK_THREE_SPARK                                  = 13468,  -- Receive how many? (# spark[/s]) One. (# spark[/s]) Three. (# spark[/s]) Twelve. (# spark[/s]) Thirty-six. (# spark[/s]) None.
        ARE_YOU_SURE_YOU_WANT_TO_EXPEND_SPARK                                         = 13469,  -- Are you sure you want to expend # spark[/s] of eminence on this?
        MAKE_THE_EXCHANGE_YES_NO                                                      = 13470,  -- Make the exchange? Yes. No.
        EXCHANGE_FOR_WHAT_ON_HAND_CURRENCIES_PROVISIONS_NONE                          = 13471,  -- Exchange for what? (On hand: #) Currencies. Provisions. None for the nonce.
        EXCHANGE_FOR_WHAT_ON_HAND_SPARKS_OF_EMINENCE                                  = 13472,  -- Exchange for what? (On hand: #) Sparks of Eminence: #. Conquest Points: #. Imperial Standing: #. Allied Notes: #. Bayld: #. Valor Pts.: #. Aslt. Pts. (Leujaoam): #. Aslt. Pts. (T. Grounds): #. Aslt. Pts. (Lebros): #. Aslt. Pts. (Periqia): #. Aslt. Pts. (Ilrusi): #. Cruor: #. Kinetic Units: #. Obs. Fragments: #. M. Plasm Corpuscles: #. Ballista Points: #. (2000 max) Unity Accolades: #. Escha Silt: #. Resistance Credits: #. Nothing for the nonce.
        EXCHANGE_HOW_MANY_POINTS_ON_HAND_ONE_THREE                                    = 13473,  -- Exchange how many points? (On hand: #) # (One). # (Three). # (Ten). # (Thirty). None.
        YOU_NOW_HAVE                                                                  = 13474,  -- You now have # [sparks of eminence/conquest points/points of imperial standing/Allied Notes/bayld/Fields of Valor points/assault points (Leujaoam)/assault points (Mamool Ja Training Grounds)/assault points (Lebros Cavern)/assault points (Periqia)/assault points (Ilrusi Atoll)/cruor/kinetic units/obsidian fragments/mweya plasm corpuscles/ballista points/Unity accolades/pinches of Escha silt/resistance credits].
        BEWARE_THAT_ANY_AMOUNT_THAT_EXCEEDS_THE_MAXIMUM                               = 13475,  -- Beware that any amount that exceeds the maximum storage limit will unceremoniously vanish into the aether.
