        EXCHANGE_FOR_WHAT_PREVIOUS_PAGE_NEXT_PAGE_NOTHING                             = 13481,  -- Exchange for what? %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. Previous page. Next page. Nothing for the nonce.
        THE_A_M_A_N_IS_PLEASED_TO                                                     = 13482,  -- The A.M.A.N. is pleased to announce a new service in which we purchase any equipment you no longer need--new or used.
        JUST_TRADE_ME_ANY_PIECE_OF_EQUIPMENT_YOU                                      = 13483,  -- Just trade me any piece of equipment you desire. I will quickly assess its value and award you with an appropriate number of reclamation marks.
