        UTILIZING_ADDITIONAL_MATERIALS_AFTER_ADDING_AN_ATTRIBUTE_CAN                  = 13845,  -- Utilizing additional materials after adding an attribute can accumulate Reinforcement Points for the equipment and increase its rank.
        INCREASING_YOUR_EQUIPMENT_S_RANK_CAN_BOOST_ITS                                = 13846,  -- Increasing your equipment's rank can boost its attributes, while some equipment can also have additional attributes added later.
