        THE_WORK_YOU_REQUEST_WILL_BE_CARRIED_OUT                                      = 13850,  -- The work you request will be carried out on-site by a specially trained Unity guide.
        COMPLETING_RECORDS_OF_EMINENCE_OBJECTIVES_AS_PART_OF                          = 13851,  -- Completing Records of Eminence objectives as part of a Unity will reward you with Unity accolades in addition to sparks of eminence.
        THESE_ACCOLADES_NOT_ONLY_SERVE_AS_A_SYMBOL                                    = 13852,  -- These accolades not only serve as a symbol of prestige, but can also be exchanged for a variety of services.
        SOME_OF_THESE_SERVICES_INCLUDE_PURCHASING_ITEMS_SECURING                      = 13853,  -- Some of these services include purchasing items, securing battle zones for hunting Wanted targets, fees for strengthening equipment, and more.
        PLEASE_NOTE_THAT_YOU_MAY_ONLY_EXCHANGE_A                                      = 13854,  -- Please note that you may only exchange a maximum of # accolades per week (Earth time).
